<?php namespace App\Services\WhatsApp; use Illuminate\Support\Facades\Http; use Illuminate\Support\Facades\Log; class RuangWaProvider implements WhatsAppProviderInterface { protected $token; public function __construct() { $this->token = env("WA_RUANGWA_TOKEN"); } public function sendMessage(string $phone, string $message): bool { try { $response = Http::post("https://ruangwa.id/v2/api/send-message.php", ["token" => $this->token, "number" => $phone, "message" => $message]); return $response->successful(); } catch (\Exception $e) { Log::error("RuangWA API Err: " . $e->getMessage()); return false; } } }
